<?php
namespace Tests\Unit;
use App\Models\ProductionBomMaterial; use App\Services\Production\ProductionRequirementCalculator; use InvalidArgumentException; use PHPUnit\Framework\TestCase;
class ProductionRequirementCalculatorTest extends TestCase { public function test_proportional_requirement_is_scaled_to_six_decimals():void{$c=new ProductionRequirementCalculator;self::assertSame('2.500000',$c->calculate('1.000000','25.000000','10.000000',ProductionBomMaterial::TYPE_PROPORTIONAL));} public function test_fixed_requirement_does_not_scale():void{$c=new ProductionRequirementCalculator;self::assertSame('3.125000',$c->calculate('3.125000','100','10',ProductionBomMaterial::TYPE_FIXED));} public function test_rounding_and_zero_guard():void{$c=new ProductionRequirementCalculator;self::assertSame('0.333333',$c->calculate('1','1','3',ProductionBomMaterial::TYPE_PROPORTIONAL));$this->expectException(InvalidArgumentException::class);$c->calculate('1','1','0',ProductionBomMaterial::TYPE_PROPORTIONAL);} }
